var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 방패 뒤에 계십시오! 돌출되면 위험합니다!","JPN":"副戦隊長殿、盾の後ろに！　体を出しては危険です！","ENG":"Deputy Commander! Please stay behind the shield! It's too dangerous to go out there by yourself!","TWN":"副隊長，請躲在盾牌後面，萬一被敵人看到會有危險的！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"난 됐고 다른 애들이나 신경 써, 발레리.","JPN":"私はいいから他の子どもたちを気にかけてあげて、ヴァレリーちゃん。","ENG":"Don't worry about me and take care of the other kids, Valeriy.","TWN":"別管我，保護孩子們，瓦萊里。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"보급품 망가지면 골치 아파지잖아. 이 난리통에 어디서 새 걸 구하니?","JPN":"補給品が壊れると困っちゃうわ。\\nこんな状況でどこで新品を手に入れればいいのかしら？","ENG":"We wouldn't want to break any equipment right now. We'd be hard-pressed to get any replacements while everything's so hectic.","TWN":"萬一補給品損壞就麻煩了，在這種亂戰中是要到哪裡去找新的補給？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"아니, 이 상황까지 와서 보급품 걱정이십니까?","JPN":"何と、こんな時に補給品の心配をなさるのですか？","ENG":"With all due respect, now's not the time to be worried about equipment, ma'am!","TWN":"不，都這種情況了，妳還擔心補給品？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"당연하지. 네가 들고 있는 방패가 우리 몸값보다 비싼데.","JPN":"当たり前じゃない。あなたの持っている盾の方が、\\n私たちの命よりよっぽど高価なの。","ENG":"Of course it is. Your shield costs more than what we make.","TWN":"當然了，你手裡的盾牌可比我們的命還要貴。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그리고 고개 숙여.","JPN":"あと、頭を下げなさい。","ENG":"And stay down.","TWN":"還有，低下頭來。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"감사합니다. 하마터면 침식체 놈에게 뒤통수가 날아갈 뻔했군요.","JPN":"感謝します。危うく侵食体の野郎に\\n後頭部をかち割られるところでした。","ENG":"Thank you. That C.O. almost sliced my head off.","TWN":"謝謝，我差點就被侵蝕體咬掉頭了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"조심해. 방호복을 입었어도 머리통이 날아가면 죽는 건 마찬가지니까.","JPN":"気をつけなさいね。防護服を着てても頭が吹っ飛んじゃえば\\n当然死んじゃうのよ。","ENG":"Be careful. Even with all that armor, you'll be pretty dead if they blow your head off.","TWN":"小心點，就算穿著防護服，被爆頭的話一樣會死。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그나저나 이상하네, 이 녀석들.","JPN":"それにしても、こいつらちょっとおかしいわね。","ENG":"Anyway, what's up with these guys?","TWN":"不過這些傢伙真奇怪啊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이번이 몇 번째 공격이더라? 잡아도 잡아도 줄어들 생각을 안 하네?","JPN":"今回で何度目の攻撃かしら？\\n仕留めても仕留めてもキリがないわ。","ENG":"How many waves have we had now? They just keep coming and coming, don't they?","TWN":"這已經是第幾波進攻了？不管怎麼打數量都沒有減少耶？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"저 빛기둥들이 나타난 뒤로 더 심해졌습니다.","JPN":"あの光の柱が現れてからさらに酷くなっています。","ENG":"It seems to be getting worse ever since that pillar of light appeared.","TWN":"自從那道光柱出現之後，情勢就變得更嚴峻了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"최전선에서 무슨 문제가 생긴 것 아닐까요?","JPN":"最前線で何か起きたのではないでしょうか？","ENG":"Perhaps something went down at the front lines?","TWN":"最前線是不是遇到了什麼麻煩？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 정찰대에서 보고가 들어왔습니다.","JPN":"副戦隊長殿、偵察隊より報告です。","ENG":"Deputy Commander, we have reports from the recon team.","TWN":"副隊長，偵察隊發來了報告。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"말해 봐, 예고르. 좋은 소식이니?","JPN":"聞かせてちょうだい、イェゴールちゃん。良い知らせかしら？","ENG":"Spill the beans, Yegor. Is it good news?","TWN":"說吧，伊高爾，是好消息嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"죄송하게도 아주 나쁜 소식입니다.","JPN":"申し訳ありませんが、極めて悪い知らせです。","ENG":"I'm afraid it's very bad news.","TWN":"很抱歉，是很壞的消息。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"7시 방향에서 몰려오고 있는 침식체 군집이 확인되었습니다.","JPN":"7時方向から侵食体の群れが殺到していることを確認しました。","ENG":"We've identified a C.O. cluster approaching from our 7 o'clock.","TWN":"他們確認到7點方向有侵蝕體群湧過來了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"타샤가 그러는데, 자기가 본 것 중 제일 큰 규모라더군요.","JPN":"ターシャが言うには、今まで見た中で最も大規模だったと。","ENG":"Tasha says its the biggest horde she's ever seen.","TWN":"塔莎說，是她見過的侵蝕體中規模最大的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"7시 방향? 지휘부가 있던 쪽이잖아?","JPN":"7時方向？　それって指揮部があった辺りよね？","ENG":"7 o'clock? But that's where the command group is!","TWN":"7點方向？那不是指揮部的方向嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그렇습니다.","JPN":"そのとおりです。","ENG":"That's correct.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"아직까지 아무 대응도 없는 걸로 봐선...... 지휘부도 이미 함락당한 것 아닐까요?","JPN":"未だに何の対応もないということは……\\n指揮部もすでに陥落しているのでは？","ENG":"Seeing as they haven't responded at all to the incoming hostiles yet... Perhaps the command group has been overrun already?","TWN":"到現在都還沒有任何應對命令……指揮部該不會已經淪陷了吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"지휘부가 당할 리가! 거기에 쟁쟁한 인물들이 얼마나 많은데!","JPN":"指揮部がやられるものか！　名だたる顔ぶれが揃っているところだぞ！","ENG":"No way! They've got folks with some serious firepower back there!","TWN":"怎麼可能！指揮部裡可是有很多頂尖好手在那裡！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"너희 둘은 애들 재정비시키고 대기해.","JPN":"あなたたち二人は子どもたちを再整備して待機しなさい。","ENG":"You two, regroup the troops and stand by.","TWN":"你們兩個將孩子們整頓一下待命。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"난 류드밀라랑 앞으로 어떻게 할지 얘기해 볼 테니까.","JPN":"私はリュドミラちゃんと今後の身の振り方を相談します。","ENG":"I'll go discuss what to do with Lyudmila.","TWN":"我去和盧德米拉討論看看接下來該怎麼做。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전대장님! 2번 엔진도 멈췄습니다! 자력 항행은 더 이상 불가능합니다!</color>","JPN":"<color=#ffd34c>戦隊長！　2番エンジンも停止しました！\\n自力航行はもはや不可能です！</color>","ENG":"<color=#ffd34c>Commander! Engine 2 is also offline! We've lost all thrust!</color>","TWN":"<color=#ffd34c>隊長！2號引擎也停了！已經沒辦法自力航行了！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>비행형 침식체, 재접근 중! 동력 부족으로 더 이상 요격할 수가 없습니다!</color>","JPN":"<color=#ffd34c>飛行型侵食体、再度接近中！\\n動力不足につき、これ以上迎撃できません！</color>","ENG":"<color=#ffd34c>Flying C.O.s approaching again! We cannot intercept due to loss of thrust!</color>","TWN":"<color=#ffd34c>飛行侵蝕體重新接近中！我們動力不足，無法迎擊！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"엔진 출력 부족은 내 염동력으로 거들겠다! 남은 동력은 전부 요격 시스템으로 보내도록!","JPN":"エンジンの出力不足は私の念動力で補う！\\n余った動力はすべて迎撃システムにまわせ！","ENG":"I'll fill the gap with my telekinesis! Divert all remaining power to the interception system!","TWN":"引擎功率不足的部分，用我的念動力來補足！剩下的動力全部集中到迎擊系統！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"의무반, 구조한 부상병들의 상태는 어떤가?","JPN":"衛生班、救助した負傷兵の様子は？","ENG":"Medic, what's the status on the rescued WIAs?","TWN":"救護隊，負傷者的情況如何？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_BUTTON_SELECT"},{"id":"L1_1","type":"dialog","speaker":"MEDIC_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>긴급 회복제는 이미 동난 지 오랩니다.</color>","JPN":"<color=#ffd34c>緊急回復剤はとっくに底をついています。</color>","ENG":"<color=#ffd34c>We ran out of emergency recovery serums a long time ago.</color>","TWN":"<color=#ffd34c>緊急恢復劑已經沒有了。</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L2_1","type":"dialog","speaker":"MEDIC_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>응급 처치로 어떻게든 시간을 끌고 있지만...... 오래 버티진 못할 겁니다.</color>","JPN":"<color=#ffd34c>何とか応急処置で持たせてはいますが……\\nそれもじきに限界を迎えるかと。</color>","ENG":"<color=#ffd34c>We're trying our best to buy more time with first aid... But they won't be able to last very long at this rate.</color>","TWN":"<color=#ffd34c>雖然用急救措施可以稍微撐一下，但……應該撐不了太久。</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"한 명 한 명이 우리와 함께 싸워 온 전우들이다.","JPN":"その一人一人が共に戦った戦友であることを忘れるな。","ENG":"Each and every one of them is our comrade.","TWN":"每個人都是和我們並肩作戰的戰友。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"목숨을 책임져 주지 않으면 누가 싸우려 들겠나! 무슨 수를 써서든 살려내도록!","JPN":"我々のために命を賭してくれたのだ。\\nそれを見捨てられる道理はない！　どんな手を使ってでも助けてみせろ！","ENG":"Nobody would be willing to fight if we don't assure them of their safe return! Do whatever it takes to keep them alive!","TWN":"如果不能對他們的生命負責，誰還願意戰鬥！無論用什麼方法都要救活他們！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MEDIC_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아, 알겠습니다! 전대장님!</color>","JPN":"<color=#ffd34c>し、承知しました！　戦隊長！</color>","ENG":"<color=#ffd34c>W-wilco! Commander!</color>","TWN":"<color=#ffd34c>知、知道了！隊長！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라. 하늘도 바쁜 건 알겠는데 잠깐 나랑 얘기 좀 해.","JPN":"リュドミラちゃん。空の方も忙しいんだろうけど、ちょっとお話があるの。","ENG":"Lyudmila. I understand things are pretty hectic up there, but we need to talk.","TWN":"盧德米拉，我知道妳很忙，但我想跟妳談一談。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_UI_BUTTON_SELECT"},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무슨 일인가, 부관. 용건만 짧게 말하도록.","JPN":"何事だ、副官。用件は手短に言いたまえ。","ENG":"What is it, adjutant? Cut to the chase.","TWN":"什麼事，副官，說重點。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"적들이 계속 쏟아져 들어오고 있어. 이제는 우리 뒤에서도 말이야.","JPN":"敵が次から次に押し寄せてるわ。悪いことに、私たちの背後からもね。","ENG":"The enemies just keep coming and coming. They're even coming from our rear now.","TWN":"敵人不斷地湧出來，現在，連我們的後方都出現敵人了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"당장 퇴각해야 돼. 이대로 가다간 전멸이야.","JPN":"ただちに撤退すべきよ。このまま行くと全滅するわ。","ENG":"We must retreat right away. Otherwise, they'll wipe us out.","TWN":"我們必須馬上撤退，不然會全滅的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"기각하겠다. 우리가 받은 명령은 전선 유지야.","JPN":"その提言は却下しよう。我々に下された命令は戦線の維持だ。","ENG":"Denied. We've been ordered to hold the front lines.","TWN":"駁回，我們收到的命令是維持戰線。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그랬지, 참.","JPN":"ええ、そうだったわね。","ENG":"Oh, that's true...","TWN":"是啊，說得很對。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그런데 그 명령 내린 지휘부랑 연락 끊긴 지 한참 되지 않았어?","JPN":"でも、その命令を下した指揮部は、\\nとっくの昔に連絡が途絶えたんじゃない？","ENG":"But when was the last time you made contact with the top brass that issued that order?","TWN":"但是下達命令的指揮部和我們已經失去聯絡好一陣子了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지휘부가 어떻게 됐는지는 중요하지 않아. 명령을 받았으면 지킬 뿐이다.","JPN":"指揮部がどうなっているかは重要ではない。\\n我々は下された命令を完遂するのみだ。","ENG":"It doesn't matter what happened to the command group. We have our orders.","TWN":"指揮部怎麼樣不重要，收到命令就要堅守到底。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"......망할 고집쟁이 같으니.","JPN":"……このクソ意地っ張り。","ENG":"Oh, you stubborn fool.","TWN":"……妳這死腦筋。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그럼 얼른 우리 애들이 침식체 떼거리에 깔려 죽지 않을 방법이나 찾아.","JPN":"だったら、うちの子どもたちが侵食体の大群に\\n踏み潰されないで済む方法を見つけてちょうだい。大至急でね。","ENG":"Then you'd better find a way to make sure our kids don't get trampled to death by the incoming C.O. stampede.","TWN":"那就快點想出不讓孩子們被侵蝕體輾過去的方法。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"죽어 버리면 명령이고 뭐고 없으니까.","JPN":"死んでしまったら命令も何もないんだから。","ENG":"We won't be able to follow orders when we're all dead.","TWN":"如果全死光了，就沒人聽命令了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......전우들을 잃고 싶지 않은 건 나도 마찬가지야.","JPN":"……戦友を失いたくないのは私とて同じだ。","ENG":"I do not wish to lose my comrades, either.","TWN":"……我也不想失去戰友。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"통신병, 아직 교신이 가능한 전대가 있나? 있다면 연결하도록.","JPN":"通信兵、まだ交信が可能な戦隊は存在しているか？\\nいるなら繋げてくれ。","ENG":"Radioman, are there any other divisions we can contact? If so, do it.","TWN":"通信兵，還有可以通訊的戰隊嗎？有的話幫我接通。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제 8 봉인전대 고르디우스의 하야미 사나에입니다.","JPN":"第8封印戦隊ゴルディウスの速水早苗でございます。","ENG":"This is Hayami Sanae of the 8th Seal Division, Gordias.","TWN":"我是第8封印戰隊哥帝爾斯的速水早苗。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_BUTTON_SELECT"},{"id":"L33_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어인 일이신지요, 전대장님.","JPN":"いかがなさいましたか？　戦隊長。","ENG":"To what do I owe this honor, Commander?","TWN":"您有什麼事嗎，隊長。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"연락이 닿는 전대는 한 곳뿐인가. 상황이 어렵군.","JPN":"連絡がつく戦隊はたったの1隊か。状況は厳しいな。","ENG":"So is this the only other division we could reach? We're in a bit of a rut here.","TWN":"現在聯絡到的只剩一個戰隊了嗎，看來情況真的很嚴峻。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"예. 저희도 벼랑 끝에 내몰린 형국이옵니다.","JPN":"ええ。私たちの方も追い込まれております。","ENG":"I fear so. Our division is likewise on the brink of total annihilation.","TWN":"是的，我們也不斷被逼到絕境。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"연합주께서 남은 병력과 함께 제 6종으로 추정되는 침식체와 맞서고 계시지만......","JPN":"連合主様は残りの兵力を率いて、第6種と推定される\\n侵食体に立ち向かっておられますが……","ENG":"Although our Alliance's leader has rallied the remainder of our troops to fight a C.O. speculated to be Category 6...","TWN":"聯盟首領正率領剩餘兵力，對抗推測為6類的侵蝕體，但……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"승산은 희박해 보입니다.","JPN":"勝てる見込みは薄いと思われます。","ENG":"Our odds seem rather grim.","TWN":"勝算渺茫。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"6종이라고? 확실한가?","JPN":"第6種だと？　間違いないのか？","ENG":"Category 6? Are you sure?","TWN":"6類？妳確定？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"증명할 수단은 없사오나, 저 공포스러운 힘을 보면 틀림없겠지요.","JPN":"証明する手立てはございません。\\nしかしながら、あのおぞましい力を見る限り間違いないでしょう。","ENG":"There is no means of proving such conjecture, but its terrifying power seems to be a good indicator.","TWN":"雖然沒有證明的方法，但從它那恐怖的力量來看，應該沒有錯。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"최악이군. 오보이길 바랐건만......","JPN":"最悪の事態だな。誤報であってほしいんだが……","ENG":"It can't get any worse than this. I was hoping that was a false report...","TWN":"太糟糕了，我本來還希望是誤報……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그리고 이제 이 통신도 마쳐야겠군요.","JPN":"さて、この通信はそろそろ切り上げさせていただきます。","ENG":"I'm afraid I'll have to conclude this call now.","TWN":"我現在要結束通信了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저는 이만 연합주님을 도우러 가야겠습니다.","JPN":"私は連合主様の加勢に向かいますゆえ。","ENG":"I must go to my leader's assistance.","TWN":"我得去幫助聯盟首領才行。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제 목숨으로 잠시나마 저 흉물을 막아설 수 있다면......","JPN":"私の命一つで、わずかな間でもあの凶々しきものを阻止できるなら……","ENG":"If I could slow down that abomination with my life, even for a moment...","TWN":"如果我能用自己的性命擋住那個怪物，哪怕是一瞬間也好……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어머님이 남긴 죗값을 만분의 일이라도 갚을 수 있겠지요.","JPN":"母が犯した罪の一万分の一程度は償えることでしょう。","ENG":"Perhaps I may atone for an infinitesimal fraction of my mother's sins.","TWN":"這樣應該也能抵消我母親餘下罪孽的萬分之一吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아직도 그런 소리를 하나! 네 어머니 일은 이미 끝났어!","JPN":"まだそんなことを言っているのか！　君の母君の件はもう済んだことだ！","ENG":"Are you still going on about that? Your mother's business is over!","TWN":"妳還在說這種話！妳母親的事情已經都過去了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이 역시 미천한 자가 살아가는 방법이오니, 이해 바라옵니다.","JPN":"これも下賤の者の生き方でございます。\\n何卒ご理解くださいませ。","ENG":"I'd ask for your kind understanding, for this is the way of life for a lowly being like myself.","TWN":"這也是我這個卑賤之人的生存方式，還請您理解。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그럼 이만. 무운을 빕니다. 류드밀라 전대장님.","JPN":"では、ご武運をお祈り申し上げます。リュドミラ戦隊長。","ENG":"Now if you’ll excuse me. I wish you best of luck, Commander Lyudmila.","TWN":"祝妳好運，盧德米拉隊長。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하야미! 하야미 부전대장!!","JPN":"速水！　速水副戦隊長！！","ENG":"Hayami! Deputy Commander Hayami!","TWN":"速水！速水副隊長！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"어떻게 됐어, 류드밀라?","JPN":"お話はどうなったの？　リュドミラちゃん。","ENG":"How did it go, Lyudmila?","TWN":"怎麼樣了，盧德米拉？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_UI_BUTTON_SELECT"},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"고르디우스도 궤멸 직전이다. 연대할 아군은 이 일대에 남아 있지 않아.","JPN":"ゴルディウスも壊滅寸前だ。\\n連携可能な友軍はこの一帯には残っていない。","ENG":"Gordias is on the verge of getting wiped out. We don't have any allies we can link up with in the area.","TWN":"哥帝爾斯也快要被擊潰了，這一帶已經沒有可以集結的友軍了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그럼 어쩔 건데?","JPN":"それじゃあ、どうするの？","ENG":"Then what are you going to do?","TWN":"那妳要怎麼做？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"남은 병력을 모두 집결시켜.","JPN":"残っている兵力を集結させろ。","ENG":"Consolidate all the remaining troops.","TWN":"集結所有剩餘兵力。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"포위망을 돌파해서 펜릴 전대와 합류한다.","JPN":"包囲網を突破し、フェンリル戦隊と合流する。","ENG":"We will break through the enemy lines and join the Fenrir Division.","TWN":"突破包圍，與芬里爾戰隊會合。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"펜릴 전대?","JPN":"フェンリル戦隊？","ENG":"Fenrir Division?","TWN":"芬里爾戰隊？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"확실히 지금 같은 상황에선 제일 믿을 만하겠지만...... 작전 중에 실종됐다던데?","JPN":"確かにこの状況では一番頼りになりそうだけど……\\n作戦中に失踪したと聞いたわよ？","ENG":"I guess they'd be the most reliable ones in a situation like this... But I heard they've gone MIA.","TWN":"現在這種情況中，他們的確是最可靠的……但我聽說他們在作戰時失蹤了呀？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하이브 컨트롤과 교신이 두절되기 전에 최전선에서 복귀했다는 보고가 있었다.","JPN":"ハイブコントロールとの交信が途絶える前に\\n最前線にて復帰を果たしたとの報告があった。","ENG":"There's a report that claims they returned from the front lines before they lost comms with the Hive Control.","TWN":"在我們與巢穴控制系統失聯之前，曾收到他們返回最前線的報告。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"관리국 최강의 부대와 합류하면 명령을 완수할 가능성도 커지겠지.","JPN":"管理局最強の部隊と合流すれば命令を完遂できる可能性も高まる。","ENG":"Linking up with the most capable unit in the Administration will maximize our chances of accomplishing our mission.","TWN":"如果我們能與管理局最強部隊會合，完成任務的可能性將會大大提升。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전대장님! 3번 엔진도 한계입니다! 지원이 필요합니다!</color>","JPN":"<color=#ffd34c>戦隊長！　3番エンジンも限界です！　至急支援を要請します！</color>","ENG":"<color=#ffd34c>Commander! Engine 3 is about to blow too! We need your help!</color>","TWN":"<color=#ffd34c>隊長！3號引擎也達到極限了！需要支援！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"나는 항행 보조 때문에 함께 싸우기 어렵다.","JPN":"私は航行補助を務めねばならん。共闘はできそうにない。","ENG":"I'm afraid I cannot fight by your side, as I'm a bit preoccupied with keeping this ship airborne.","TWN":"我要輔助航行，無法參加戰鬥。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전대원들을 잘 부탁한다. 알렉스.","JPN":"戦隊員たちを頼むぞ。アレックス。","ENG":"I'm counting on you to take care of our troops, Alex.","TWN":"雅蕾克絲，隊員們就拜託妳了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"명령이 중요한지 애들이 중요한지 하나만 골라.","JPN":"命令を大事にするのか、子どもたちを大事にするのか、\\nどっちか選んでちょうだい。","ENG":"Why can't she just choose between our orders and the kids?","TWN":"到底是命令重要還是隊員重要，妳選一個好不好。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이럴 때 보면 참 영락없는 어린애라니까.","JPN":"こういう時はまるでワガママなお子様みたいね。","ENG":"She's such a little child when it comes to things like this.","TWN":"這種時候就跟小孩沒兩樣。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"자, 다들 주목.","JPN":"さあ、みんな注目してちょうだいね。","ENG":"Alright, attention everyone.","TWN":"聽著，全員注意！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"지금부터 우리는 펜릴 전대와 합류하러 최전선으로 간다.","JPN":"今から私たちはフェンリル戦隊と合流するために最前線へ向かいます。","ENG":"We will head to the front lines and link up with the Fenrir Division.","TWN":"我們現在要去最前線，與芬里爾戰隊會合。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"최전선이면 6종 침식체가 대거 나타났다는 곳 아닙니까?","JPN":"最前線は第6種侵食体が多数出現しているはずでは？","ENG":"But isn't that where the Category 6 C.O.s appeared?","TWN":"最前線不是出現很多6類侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"저희 중에 카운터는 부전대장님과 전대장님, 두 분뿐입니다.","JPN":"我々の中にカウンターは副戦隊長殿と戦隊長、お二人しかおられません。","ENG":"There are only two Counters among us. You and the Commander.","TWN":"我們當中只有副隊長和隊長是制裁者。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"자칫 잘못하면 오히려 짐이 될지도 모릅니다.","JPN":"下手をすると、かえって足手まといになるかもしれません。","ENG":"We might just slow you down.","TWN":"如果我們搞砸了，可能會拖累你們的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"무슨 바보 같은 소리니? 전술 교육 받을 때 졸았어?","JPN":"何おバカなことを言ってるのかしら。戦術教育で習ったでしょう？","ENG":"Don't be ridiculous! Did you doze off during your tactics theory course?","TWN":"你在說什麼傻話？你在戰術教育課程的時候是在打瞌睡嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"<color=#ffd34c>전쟁은 카운터 혼자 하는 게 아니다. 지원 병력 없이는 결국 숫자에 압살당한다.</color>","JPN":"<color=#ffd34c>戦争はカウンター一人でやるものではない。\\n支援兵力がなければ、結局は数に押し潰される。</color>","ENG":"<color=#ffd34c>A war is not fought by Counters alone. They too can face defeat when outnumbered without support troops.</color>","TWN":"<color=#ffd34c>戰爭不是制裁者一個人的事。如果沒有支援兵力，終究會被數量壓倒。</color>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"어떻습니까? 제대로 맞췄죠?","JPN":"いかがですか？　正解ですよね？","ENG":"How's that? Did I get it right?","TWN":"怎麼樣？我說對了吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"발레리는 제대로 들었네. 대견한데?","JPN":"ヴァレリーちゃんは授業中に居眠りしなかったのね。えらいえら～い。","ENG":"Well, at least Valeriy was paying attention. I'm impressed!","TWN":"看來瓦萊里有好好聽課，很不錯喔？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"난 예고르랑 다른 애들도 자기 역할에 좀 더 자부심을 가져 주면 좋겠는데, 어려운 부탁일까?","JPN":"私、イェゴールちゃんや他のみんなにも自分の役目に\\nプライドを持ってほしいの。そんなに難しいお願いかしら？","ENG":"Yegor, I wish you and the other kids would take more pride in what you do. Is that too much to ask?","TWN":"我希望伊高爾和其他孩子們，也能更以自己肩負的職責為榮，這會很難做到嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"아, 아닙니다! 부전대장님!","JPN":"と、とんでもございません！　副戦隊長殿！","ENG":"N-no, ma'am! Deputy Commander!","TWN":"不、不會！副隊長！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 알아 들었으면 빠릿빠릿하게 움직여야지?","JPN":"わかってもらえて嬉しいわ。ではさっそくテキパキ動きましょうね。","ENG":"Okay. Then get your butts moving!","TWN":"很好，既然聽懂了那就快點行動吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"관리국 제 9 포격전대 메이즈. 전투 준비.","JPN":"管理局第9砲撃戦隊メイズ、戦闘用意。","ENG":"The 9th Administration Artillery Division, Maze. Prepare to engage.","TWN":"管理局第9炮擊戰隊梅茲，準備戰鬥。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"적의 포위망을 돌파해 활로를 만든다!","JPN":"敵の包囲網を突破し、活路を切り開くわ！","ENG":"We're going to break through the enemy lines and secure our escape route!","TWN":"突破包圍，殺出一條血路！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};